class Solution:
    def printLIS(self, nums: list[int]) -> None:
        n = len(nums)
        dp = [1] * n
        prev = [-1] * n
        for i in range(1, n):
            for j in range(i):
                if nums[i] > nums[j] and dp[i] < dp[j] + 1:
                    dp[i] = dp[j] + 1
                    prev[i] = j
        max_len_idx = max(range(n), key=lambda i: dp[i])
        max_len = dp[max_len_idx]
        print(max_len, end=' ')
        seq = []
        idx = max_len_idx
        while idx != -1:
            seq.append(nums[idx])
            idx = prev[idx]
        for i in range(max_len - 1, -1, -1):
            print(seq[i], end=' ' if i > 0 else '\n')

