#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    void printLIS(vector<int>& nums) {
        int n = nums.size();
        vector<int> dp(n, 1);
        vector<int> prev(n, -1);
        for (int i = 1; i < n; i++) {
            for (int j = 0; j < i; j++) {
                if (nums[i] > nums[j] && dp[i] < dp[j] + 1) {
                    dp[i] = dp[j] + 1;
                    prev[i] = j;
                }
            }
        }
        int max_len_idx = distance(dp.begin(), max_element(dp.begin(), dp.end()));
        int max_len = dp[max_len_idx];
        cout << max_len << ' ';
        vector<int> seq;
        int idx = max_len_idx;
        while (idx != -1) {
            seq.push_back(nums[idx]);
            idx = prev[idx];
        }
        for (int i = max_len - 1; i >= 0; i--) {
            cout << seq[i] << (i > 0 ? ' ' : '\n');
        }
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    sol.printLIS(nums);
    return 0;
}
